// GET / - list users
router.get("/", (req, res) => {
  res.json(users);
});

// GET /:id - get user
router.get("/:id", (req, res) => {
  const user = users.find((u) => u.id === parseInt(req.params.id));
  if (!user) {
    return res.status(404).json({ error: "User not found" });
  }
  res.json(user);
});

// POST / - create user
router.post("/", (req, res) => {
  const { name, email } = req.body;

  if (!name || !email) {
    return res.status(400).json({ error: "Name and email are required" });
  }

  const newUser = {
    id: Math.max(...users.map((u) => u.id), 0) + 1,
    name,
    email,
  };

  users.push(newUser);
  res.status(201).json(newUser);
});

// DELETE /:id - delete user
router.delete("/:id", (req, res) => {
  const index = users.findIndex((u) => u.id === parseInt(req.params.id));

  if (index === -1) {
    return res.status(404).json({ error: "User not found" });
  }

  const deletedUser = users.splice(index, 1);
  res.json(deletedUser[0]);
});

// Mount router
app.use("/api/users", router);

// Claude-powered endpoint for user management assistance
app.post("/api/assist", async (req, res) => {
  const { query } = req.body;

  if (!query) {
    return res.status(400).json({ error: "Query is required" });
  }

  const message = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 1024,
    messages: [
      {
        role: "user",
        content: `You are a helpful assistant for a user management API. Current users: ${JSON.stringify(users)}. User query: ${query}. Provide helpful information or suggestions.`,
      },
    ],
  });

  const responseText =
    message.content[0].type === "text" ? message.content[0].text : "";

  res.json({ response: responseText });
});

// Start server
