        'created_at': '2024-01-14T14:20:00Z'
    }
}

next_order_id = 3


@orders_bp.route('/', methods=['GET'])
def list_orders():
    """List all orders"""
    orders_list = list(orders_db.values())
    return jsonify({
        'success': True,
        'data': orders_list,
        'count': len(orders_list)
    }), 200


@orders_bp.route('/<int:order_id>', methods=['GET'])
