    """Get a specific order by ID"""
    if order_id not in orders_db:
        return jsonify({
            'success': False,
            'error': f'Order {order_id} not found'
        }), 404

    return jsonify({
        'success': True,
        'data': orders_db[order_id]
    }), 200


@orders_bp.route('/', methods=['POST'])
