import Anthropic from "@anthropic-ai/sdk";
import express from "express";

const client = new Anthropic();
const router = express.Router();

// In-memory storage for posts
const posts = [];

// GET / - List all posts
router.get("/", (req, res) => {
  res.json(posts);
});

// GET /:slug - Get post by slug
router.get("/:slug", (req, res) => {
  const post = posts.find((p) => p.slug === req.params.slug);
  if (!post) {
    return res.status(404).json({ error: "Post not found" });
  }
  res.json(post);
});

// POST / - Create post
router.post("/", async (req, res) => {
  const { title, content } = req.body;

  if (!title || !content) {
    return res.status(400).json({ error: "Title and content are required" });
  }

  // Use Claude to generate a slug from the title
  const message = await client.messages.create({
    model: "claude-3-5-sonnet-20241022",
    max_tokens: 100,
    messages: [
      {
        role: "user",
        content: `Generate a URL-friendly slug from this title. Return only the slug, no explanation. Title: "${title}"`,
      },
    ],
  });

  const slug = message.content[0].text
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");

  // Check if slug already exists
  if (posts.some((p) => p.slug === slug)) {
    return res.status(400).json({ error: "A post with this slug already exists" });
  }

  const newPost = {
    id: posts.length + 1,
    slug,
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /:slug - Update post
router.put("/:slug", async (req, res) => {
  const { title, content } = req.body;
  const post = posts.find((p) => p.slug === req.params.slug);

  if (!post) {
    return res.status(404).json({ error: "Post not found" });
  }

  if (title) {
    post.title = title;

    // Use Claude to generate a new slug if title changed
    const message = await client.messages.create({
      model: "claude-3-5-sonnet-20241022",
      max_tokens: 100,
      messages: [
        {
          role: "user",
          content: `Generate a URL-friendly slug from this title. Return only the slug, no explanation. Title: "${title}"`,
        },
      ],
    });

    const newSlug = message.content[0].text
      .trim()
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, "-")
      .replace(/^-+|-+$/g, "");

    // Check if new slug conflicts with existing posts
    if (newSlug !== post.slug && posts.some((p) => p.slug === newSlug)) {
      return res.status(400).json({ error: "A post with this slug already exists" });
    }

    post.slug = newSlug;
  }

  if (content) {
    post.content = content;
  }

  post.updatedAt = new Date().toISOString();
  res.json(post);
});

export default router;
```
